import{$,$$,emit,t,prefersReducedMotion,clamp,announce}from"./utils.js";let container;let screens=[];let activeIndex=0;let locked=false;let observer=null;let rebuilding=false;export function getActiveIndex(){if(container?.clientHeight){return clamp(Math.round(container.scrollTop/container.clientHeight),0,Math.max(screens.length-1,0));}
return activeIndex;}
export function getScreens(){return screens;}
export function init(){container=$("#snap");bindScreens();initWheelAndKeys();initHash();initGotoButtons();}
export function rebind(keepIndex=0){rebuilding=true;bindScreens();goTo(keepIndex,true);requestAnimationFrame(()=>{rebuilding=false;});}
function bindScreens(){screens=$$(".screen",container);buildRail();observeActive();}
let io=null;function observeActive(){io?.disconnect();io=new IntersectionObserver((entries)=>{for(const entry of entries){if(!entry.isIntersecting)continue;const index=screens.indexOf(entry.target);if(index===-1||index===activeIndex&&!rebuilding)continue;setActive(index);}},{root:container,threshold:0.6},);screens.forEach((s)=>io.observe(s));}
function setActive(index){activeIndex=index;const section=screens[index];const dishId=section.classList.contains("dish")?section.id:null;updateRail(index);updateHash(section);announceScreen(section,index);emit("dish:active",{index,section,dishId,mood:section.dataset.mood||"paper"});}
function announceScreen(section,index){if(section.classList.contains("dish")){const dishes=screens.filter((s)=>s.classList.contains("dish"));const i=dishes.indexOf(section)+1;announce(`${t("dishOf", { i, n: dishes.length })} — ${section.getAttribute("aria-label")}`);}else{announce(section.getAttribute("aria-label")||"");}}
let pageTween=null;function settleTween(){container.classList.remove("is-tweening");setTimeout(()=>{locked=false;},180);}
export function goTo(index,instant=false){index=clamp(index,0,screens.length-1);const top=index*container.clientHeight;if(instant||prefersReducedMotion()||!window.gsap||document.visibilityState==="hidden"){pageTween?.kill();container.scrollTo({top,behavior:"auto"});return;}
pageTween?.kill();locked=true;container.classList.add("is-tweening");const proxy={v:container.scrollTop};pageTween=gsap.to(proxy,{v:top,duration:0.8,ease:"power3.inOut",onUpdate:()=>{container.scrollTop=proxy.v;},onComplete:settleTween,onInterrupt:settleTween,});}
function initWheelAndKeys(){if(!prefersReducedMotion()&&window.Observer){gsap.registerPlugin(Observer);observer=Observer.create({target:container,type:"wheel",preventDefault:true,tolerance:8,onDown:()=>step(1),onUp:()=>step(-1),});}
document.addEventListener("keydown",(e)=>{if(e.defaultPrevented)return;const sheet=$("#order-sheet");if(sheet?.open)return;const el=document.activeElement;const tag=el?.tagName;if(tag==="INPUT"||tag==="TEXTAREA"||el?.isContentEditable)return;const focusIsInteractive=tag==="BUTTON"||tag==="A"||tag==="SELECT"||tag==="SUMMARY";switch(e.key){case"ArrowDown":case"PageDown":e.preventDefault();step(1);break;case" ":if(focusIsInteractive)return;e.preventDefault();step(e.shiftKey?-1:1);break;case"ArrowUp":case"PageUp":e.preventDefault();step(-1);break;case"Home":e.preventDefault();goTo(0);break;case"End":e.preventDefault();goTo(screens.length-1);break;}});}
function step(dir){if(locked)return;const current=Math.round(container.scrollTop/container.clientHeight);goTo(current+dir);}
let railGroups=[];function buildRail(){const rail=$("#rail");rail.setAttribute("aria-label",t("railAria"));rail.innerHTML="";railGroups=[];let current=null;screens.forEach((s,i)=>{const key=s.dataset.rail||s.id||`screen-${i}`;if(!current||current.key!==key){current={key,first:i,last:i,label:s.getAttribute("aria-label")||`Screen ${i + 1}`,};railGroups.push(current);}else{current.last=i;}});railGroups.forEach((g)=>{const b=document.createElement("button");b.type="button";b.setAttribute("aria-label",g.label);b.addEventListener("click",()=>goTo(g.first));rail.append(b);});updateRail(activeIndex);}
function updateRail(index){const btns=$$("#rail button");railGroups.forEach((g,gi)=>{if(index>=g.first&&index<=g.last)btns[gi]?.setAttribute("aria-current","true");else btns[gi]?.removeAttribute("aria-current");});}
let hashTimer;function updateHash(section){clearTimeout(hashTimer);hashTimer=setTimeout(()=>{const id=section.id||"";if(id&&id!=="top")history.replaceState(null,"",`#${id}`);else history.replaceState(null,"",location.pathname+location.search);},300);}
function initHash(){const id=location.hash.slice(1);if(!id)return;const target=screens.findIndex((s)=>s.id===id);if(target>0)goTo(target,true);}
function initGotoButtons(){document.addEventListener("click",(e)=>{const el=e.target.closest("[data-goto]");if(!el)return;e.preventDefault();const v=el.dataset.goto;const n=Number(v);const index=Number.isNaN(n)?screens.findIndex((s)=>s.id===v):n;if(index>=0)goTo(index);});}
export function initNavAutoHide(){const nav=$("#nav");let lastTop=0;let ticking=false;container.addEventListener("scroll",()=>{if(ticking)return;ticking=true;requestAnimationFrame(()=>{const top=container.scrollTop;const delta=top-lastTop;const onEdges=top<container.clientHeight*0.5||top>container.scrollHeight-container.clientHeight*1.5;if(onEdges||delta<-4)nav.dataset.hidden="false";else if(delta>24)nav.dataset.hidden="true";lastTop=top;ticking=false;});},{passive:true});const settle=()=>{nav.dataset.hidden="false";};if("onscrollend"in container){container.addEventListener("scrollend",settle);}else{let t2;container.addEventListener("scroll",()=>{clearTimeout(t2);t2=setTimeout(settle,180);},{passive:true});}}